+/// Parse a PRAGMA value as a finite `f64`.
+///
+/// Accepts integer and float literals (with optional unary negation), and
+/// bare-identifier forms like `PRAGMA fsqlite.retry_slo_alpha = 0.05`
+/// where the parser hands back the RHS as an unquoted column reference.
+/// Rejects NaN / infinity to keep downstream math well-defined.
+fn parse_pragma_float(value: &fsqlite_ast::PragmaValue, what: &str) -> Result<f64> {
+    let expr = match value {
+        fsqlite_ast::PragmaValue::Assign(e) | fsqlite_ast::PragmaValue::Call(e) => e,
+    };
+    let raw: f64 = match expr {
+        Expr::Literal(Literal::Integer(n), _) => {
+            #[allow(clippy::cast_precision_loss)]
+            let f = *n as f64;
+            f
+        }
+        Expr::Literal(Literal::Float(f), _) => *f,
+        Expr::UnaryOp {
+            op: UnaryOp::Negate,
+            expr,
+            ..
+        } => match expr.as_ref() {
+            Expr::Literal(Literal::Integer(n), _) => {
+                #[allow(clippy::cast_precision_loss)]
+                let f = -(*n as f64);
+                f
+            }
+            Expr::Literal(Literal::Float(f), _) => -*f,
+            _ => {
+                return Err(FrankenError::Internal(format!(
+                    "PRAGMA {what} must be a finite number"
+                )));
+            }
+        },
+        Expr::Literal(Literal::String(s), _) => s.parse::<f64>().map_err(|_| {
+            FrankenError::Internal(format!("PRAGMA {what} must be a finite number, got `{s}`"))
+        })?,
+        Expr::Column(col_ref, _) if col_ref.table.is_none() => {
+            col_ref.column.parse::<f64>().map_err(|_| {
+                FrankenError::Internal(format!(
+                    "PRAGMA {what} must be a finite number, got `{}`",
+                    col_ref.column
+                ))
+            })?
+        }
+        _ => {
+            return Err(FrankenError::Internal(format!(
+                "PRAGMA {what} must be a finite number"
+            )));
+        }
+    };
+    if !raw.is_finite() {
+        return Err(FrankenError::Internal(format!(
+            "PRAGMA {what} must be finite, got {raw}"
+        )));
+    }
+    Ok(raw)
+}
